                # specified lookups, e.g. if `limit_choices_to = {'__year': 2023}`,
                # `__year__month` lookup is also allowed.
                lookup_until_fk_lookup = LOOKUP_SEP.join(lookup.split(LOOKUP_SEP)[:len(fk_lookup_parts)])
