"""
    sphinx.ext.autodoc.typehints
    ~~~~~~~~~~~~~~~~~~~~~~~~~~~~

    Generating content for autodoc using typehints

    :copyright: Copyright 2007-2021 by the Sphinx team, see AUTHORS.
    :license: BSD, see LICENSE for details.
"""

import re
from typing import Any, Dict, Set

from docutils import nodes
from docutils.nodes import Element

from sphinx import addnodes
from sphinx.application import Sphinx
from sphinx.util import inspect, logging
from sphinx.util.typing import stringify

logger = logging.getLogger(__name__)


def record_typehints(app: Sphinx, objtype: str, name: str, obj: Any,
                     options: Dict, args: str, retann: Any) -> None:
    """Record type hints to env object."""
    try:
        if callable(obj):
            annotations = app.env.temp_data.setdefault('annotations', {})
            annotation = annotations.setdefault(name, {})
            sig = inspect.signature(obj, follow_wrapped=True)
            for param in sig.parameters.values():
                if param.annotation is not param.empty:
                    annotation[param.name] = param.annotation
            if sig.return_annotation is not sig.empty:
                annotation['return'] = sig.return_annotation
    except (TypeError, ValueError):
        pass


def merge_typehints(app: Sphinx, domain: str, objtype: str, contentnode: Element) -> None:
    if domain != 'py':
        return
    if app.config.autodoc_typehints not in ('both', 'description'):
        return

    try:
        signature = contentnode.parent[addnodes.desc_signature]
    except (KeyError, IndexError):
        return

    fullname = signature['module'] + '.' + signature['fullname']
    annotations = app.env.temp_data.get('annotations', {})
    if annotations.get(fullname, {}):
        field_lists = [n for n in contentnode if isinstance(n, nodes.field_list)]
        if field_lists == []:
            field_list = insert_field_list(contentnode)
            field_lists.append(field_list)

        for field_list in field_lists:
            if app.config.autodoc_typehints_description_target == "all":
                modify_field_list(field_list, annotations[fullname], suppress_rtype=True)
            elif app.config.autodoc_typehints_description_target == "documented_params":
                augment_descriptions_with_types(field_list, annotations[fullname], force_rtype=True)
            else:
                augment_descriptions_with_types(field_list, annotations[fullname], force_rtype=False)


def insert_field_list(node: Element) -> nodes.field_list:
    field_list = nodes.field_list()
    desc = [n for n in node if isinstance(n, addnodes.desc_content)]
    if desc:
        # insert function signature at top of existing field list
        desc[0].insert(0, field_list)
    else:
        node.append(field_list)
    return field_list


def modify_field_list(node: nodes.field_list, annotations: Dict[str, Any], suppress_rtype: bool = True) -> None:
    arguments = {}
    fields_to_remove = []

    for field in node:
        field_name = field[0].astext()
        parts = re.split(' +', field_name)
        if parts[0] == 'param':
            if len(parts) == 2:
                # :param xxx:
                arg = arguments.setdefault(parts[1], {})
                arg['param'] = field
            elif len(parts) == 3:
                # :param type xxx: or :param xxx type:
                name = parts[1]
                if parts[2] in ('type', 'kwtype'):
                    arg = arguments.setdefault(name, {})
                    arg['type'] = field
                else:
                    name, typ = parts[1], ' '.join(parts[2:])
                    arg = arguments.setdefault(name, {})
                    arg['param'] = field
        elif parts[0] == 'type':
            name = ' '.join(parts[1:])
            arg = arguments.setdefault(name, {})
            arg['type'] = field
        elif parts[0] in ('return', 'returns'):
            arguments['return'] = field
        elif parts[0] == 'rtype':
            arguments['rtype'] = field

    for name, annotation in annotations.items():
        if name == 'return':
            continue

        arg = arguments.get(name, {})
        if not arg.get('type'):
            field = nodes.field()
            field += nodes.field_name('', 'type ' + name)
            field += nodes.field_body('', nodes.paragraph('', stringify(annotation)))
            node += field
        else:
            field = arg['type']
            field[1].clear()
            field[1] += nodes.paragraph('', stringify(annotation))

    if 'return' in annotations:
        if not arguments.get('rtype'):
            field = nodes.field()
            field += nodes.field_name('', 'rtype')
            field += nodes.field_body('', nodes.paragraph('', stringify(annotations['return'])))
            node += field
        else:
            field = arguments['rtype']
            field[1].clear()
            field[1] += nodes.paragraph('', stringify(annotations['return']))

    if suppress_rtype and 'return' in annotations:
        if arguments.get('rtype'):
            fields_to_remove.append(arguments['rtype'])

    for field in fields_to_remove:
        node.remove(field)


def augment_descriptions_with_types(node: nodes.field_list, annotations: Dict[str, Any], force_rtype: bool) -> None:
    has_description = set()  # type: Set[str]
    has_type = set()  # type: Set[str]

    for field in node:
        field_name = field[0].astext()
        parts = re.split(' +', field_name)
        if parts[0] == 'param':
            if len(parts) == 2:
                # :param xxx:
                has_description.add(parts[1])
            elif len(parts) == 3:
                # :param type xxx: or :param xxx type:
                name = parts[1]
                if parts[2] in ('type', 'kwtype'):
                    has_type.add(name)
                    has_description.add(name)
                else:
                    has_description.add(name)
        elif parts[0] == 'type':
            name = ' '.join(parts[1:])
            has_type.add(name)
        elif parts[0] in ('return', 'returns'):
            has_description.add('return')
        elif parts[0] == 'rtype':
            has_type.add('return')

    # Add 'type' for parameters which has annotations but no 'type' field
    for name, annotation in annotations.items():
        if name == 'return':
            continue

        if has_description.get(name) and not has_type.get(name):
            field = nodes.field()
            field += nodes.field_name('', 'type ' + name)
            field += nodes.field_body('', nodes.paragraph('', stringify(annotation)))
            node += field

    # Add 'rtype' if 'return' is annotated and ( not has 'rtype' or forced )
    if 'return' in annotations:
        rtype = annotations['return']
        if not has_type.get('return') or force_rtype:
            field = nodes.field()
            field += nodes.field_name('', 'rtype')
            field += nodes.field_body('', nodes.paragraph('', stringify(rtype)))
            node += field


def setup(app: Sphinx) -> Dict[str, Any]:
    app.connect('autodoc-process-signature', record_typehints)
    app.connect('autodoc-process-docstring', merge_typehints)

    return {
        'version': 'builtin',
        'parallel_read_safe': True,
        'parallel_write_safe': True,
    }
