                return ':py:class:`%s`' % cls.__name__
            elif mode == 'fully-qualified-except-typing':
                return ':py:class:`%s`' % cls.__name__
            else:
                return ':py:class:`typing.%s`' % cls.__name__
        elif (inspect.isNewType(cls) or
              inspect.isclass(cls) or
              inspect.isfunction(cls) or
              inspect.isbuiltin(cls)):
