                if mode == 'smart':
                    return ':py:class:`%s`' % cls.__name__
                else:
                    return ':py:class:`%s`' % cls.__name__
            elif cls.__module__ == 'typing':
                if mode == 'smart':
                    return ':py:class:`~typing.%s`' % cls.__name__
                elif mode == 'fully-qualified-except-typing':
                    return ':py:class:`%s`' % cls.__name__
                else:
                    return ':py:class:`typing.%s`' % cls.__name__
            else:
                if mode == 'smart':
                    return ':py:class:`~%s.%s`' % (cls.__module__, cls.__name__)
                elif mode == 'fully-qualified-except-typing':
                    return ':py:class:`%s.%s`' % (cls.__module__, cls.__name__)
                else:
