            elif mode == 'fully-qualified-except-typing':
                return ':py:class:`%s`' % cls._name
            else:
                return ':py:class:`typing.%s`' % cls._name
        elif hasattr(cls, '__qualname__'):
            if mode == 'smart':
                return ':py:class:`~%s.%s`' % (cls.__module__, cls.__qualname__)
            elif mode == 'fully-qualified-except-typing':
                return ':py:class:`%s.%s`' % (cls.__module__, cls.__qualname__)
            else:
