class DeferredAttribute:
    """
    A wrapper for a deferred-loading field. When the value is read from this
    object the first time, the query is executed.
    """
    def __init__(self, field_name):
        self.field_name = field_name

    def __repr__(self):
        return "<%s: %s>" % (self.__class__.__name__, self.field_name)

    def __getattr__(self, attr):
        # This gets called only when an attribute wasn't found the usual ways.

        # Bail out early if we don't have a '__dict__' (which raises
        # AttributeError), because otherwise the below hasattr() will result in
        # infinite recursion (really confusing and hard to debug).
        self.__dict__

        # Since we're the descriptor, we're probably being accessed from a class,
        # so give the normal AttributeError behavior.
        raise AttributeError(
            "'%s' object has no attribute '%s'" % (type(self).__name__, attr)
        )

    def __set__(self, instance, value):
        """
        Deferred loading attributes can be set normally (which means there will
        never be a database lookup involved.
        """
        instance.__dict__[self.field_name] = value

    def __get__(self, instance, cls=None):
        """
        Retrieve and caches the value from the datastore on the first lookup.
        Return the cached value.
        """
        if instance is None:
            return self
        data = instance.__dict__
        field_name = self.field_name
        if field_name not in data:
            # Let's see if the field is part of the parent chain. If so we
            # might be able to reuse the already loaded value. Refs #18343.
            val = self._check_parent_chain(instance)
            if val is None:
                instance.refresh_from_db(fields=[field_name])
                val = getattr(instance, field_name)
            data[field_name] = val
        return data[field_name]

    def _check_parent_chain(self, instance):
        """
        Check if the field value can be fetched from a parent field already
        loaded in the instance. This can be done if the to-be fetched
        field is a primary key field.
        """
        opts = instance._meta
        link_field = opts.get_ancestor_link(self.field_name)
        if getattr(link_field, 'primary_key', False):
            return getattr(instance, link_field.attname)
        return None


