class ExpressionList(Func):
    """
    An expression containing multiple expressions. (a, b, c)
    """
    template = '(%(expressions)s)'

    def __init__(self, *expressions, **extra):
        if len(expressions) == 1 and hasattr(expressions[0], '__iter__') and not isinstance(expressions[0], str):
            # Ensure that expressions are always a tuple, so that when
            # _combine is used, the expression will not be substituted in place.
            expressions = tuple(expressions[0])
        super().__init__(*expressions, **extra)

    def __str__(self):
        return "({})".format(', '.join(str(arg) for arg in self.source_expressions))

    def __repr__(self):
        return "{}({})".format(
            self.__class__.__name__,
            ', '.join(repr(arg) for arg in self.source_expressions)
        )

    def as_oracle(self, compiler, connection, **extra_context):
        # Oracle doesn't allow EXISTS() to be compared to NULL/non-NULL, so
        # wrap such expressions in a CASE WHEN expression. Change True to 1 and
        # False to 0 because Oracle considers them database-specific.
        if self.source_expressions:
            first_expression = self.source_expressions[0]
            if isinstance(first_expression, Exists):
                return Case(When(first_expression, then=1), default=0).as_oracle(compiler, connection)
        return self.as_sql(compiler, connection, **extra_context)


@deconstructible
class OrderBy(Expression):
    template = '%(expression)s %(ordering)s'
    conditional = False

    def __init__(self, expression, descending=False, nulls_first=False, nulls_last=False):
        if nulls_first and nulls_last:
            raise ValueError('nulls_first and nulls_last are mutually exclusive')
        self.nulls_first = nulls_first
        self.nulls_last = nulls_last
        self.descending = descending
        if not hasattr(expression, 'resolve_expression'):
            raise ValueError('expression must be an expression')
        super().__init__(output_field=expression._output_field_or_none)
        self.source_expression = expression

    def __repr__(self):
        return "{}({}, descending={})".format(
            self.__class__.__name__, self.source_expression, self.descending)

    def get_source_expressions(self):
        return [self.source_expression]

    def set_source_expressions(self, exprs):
        self.source_expression = exprs[0]

    def as_sql(self, compiler, connection, **extra_context):
        template = self.template
        if connection.features.supports_over_clause:
            if self.nulls_last:
                template = '%s NULLS LAST' % template
            elif self.nulls_first:
                template = '%s NULLS FIRST' % template

        expression_sql, params = compiler.compile(self.source_expression)
        placeholders = {
            'expression': expression_sql,
            'ordering': 'DESC' if self.descending else 'ASC',
        }
        params *= template.count('%(expression)s')
        template = template % placeholders

        return template, params

    def as_sqlite(self, compiler, connection, **extra_context):
        template = self.template
        if self.nulls_last:
            template = '%s NULLS LAST' % template
        elif self.nulls_first:
            template = '%s NULLS FIRST' % template
        return self.as_sql(compiler, connection, template=template, **extra_context)

    def as_mysql(self, compiler, connection, **extra_context):
        template = self.template
        if self.nulls_last:
            template = 'ISNULL(%(expression)s), %(expression)s %(ordering)s'
        elif self.nulls_first:
            template = 'ISNULL(%(expression)s) DESC, %(expression)s %(ordering)s'
        return self.as_sql(compiler, connection, template=template, **extra_context)

    def get_group_by_cols(self, alias=None):
        cols = []
        for source in self.get_source_expressions():
            cols.extend(source.get_group_by_cols(alias))
        return cols

    def reverse_ordering(self):
        self.descending = not self.descending
        if self.nulls_first or self.nulls_last:
            self.nulls_first = not self.nulls_first
            self.nulls_last = not self.nulls_last
        return self

    def asc(self, **kwargs):
        kwargs.setdefault('nulls_first', self.nulls_first)
        kwargs.setdefault('nulls_last', self.nulls_last)
        return self.copy().reverse_ordering().reverse_ordering(**kwargs)

    def desc(self, **kwargs):
        kwargs.setdefault('nulls_first', self.nulls_first)
        kwargs.setdefault('nulls_last', self.nulls_last)
        return self.copy().reverse_ordering(**kwargs)


