            # a singleton and moves it to the head of the string
            s = Permutation(expr.cyclic_form).__str__()[len('Cycle'):]
            last = s.rfind('(')
            if not last == 0 and ',' not in s[last:]:
                s = s[last:] + s[:last]
            s = s.replace(',', '')
